<script>
  (function () {
    var root = document.getElementById('petcura-info-tabs');
    if (!root) return;

    var tabs = Array.prototype.slice.call(root.querySelectorAll('.pc-tab'));
    var panels = {
      'pc-tab-vet': root.querySelector('#pc-panel-vet'),
      'pc-tab-ingredients': root.querySelector('#pc-panel-ingredients'),
      'pc-tab-feeding': root.querySelector('#pc-panel-feeding'),
      'pc-tab-benefits': root.querySelector('#pc-panel-benefits')
    };

    function activate(tabId, focusPanel) {
      tabs.forEach(function (btn) {
        var isActive = btn.id === tabId;
        btn.classList.toggle('is-active', isActive);
        btn.setAttribute('aria-selected', isActive ? 'true' : 'false');
        btn.tabIndex = isActive ? 0 : -1;

        var panel = panels[btn.id];
        if (!panel) return;

        if (isActive) {
          panel.removeAttribute('hidden');
          panel.style.display = '';
        } else {
          panel.setAttribute('hidden', '');
          panel.style.display = 'none';
        }
      });

      if (focusPanel) {
        var p = panels[tabId];
        if (p) p.focus({ preventScroll: true });
      }
    }

    function nextTab(currentIndex, dir) {
      var n = tabs.length;
      var idx = (currentIndex + dir + n) % n;
      tabs[idx].focus();
      activate(tabs[idx].id, false);
    }

    tabs.forEach(function (btn, idx) {
      btn.addEventListener('click', function () { activate(btn.id, false); });

      btn.addEventListener('keydown', function (e) {
        var key = e.key;
        if (key === 'ArrowRight') { e.preventDefault(); nextTab(idx, +1); }
        if (key === 'ArrowLeft')  { e.preventDefault(); nextTab(idx, -1); }
        if (key === 'Home')       { e.preventDefault(); tabs[0].focus(); activate(tabs[0].id, false); }
        if (key === 'End')        { e.preventDefault(); tabs[tabs.length - 1].focus(); activate(tabs[tabs.length - 1].id, false); }
        if (key === 'Enter' || key === ' ') { e.preventDefault(); activate(btn.id, true); }
      });
    });

    // Init
    activate('pc-tab-vet', false);
  })();
</script>

